const body = $input.first().json.body || $input.first().json;
const scenarioId = body.scenario_id || null;
const freetext = body.freetext || body.description || '';
const industry = body.industry || 'universal';
const platform = body.platform || 'windows';
const needsEnrichment = !scenarioId && freetext.length > 0;
return [{ json: { scenario_id: scenarioId, freetext: freetext, industry: industry, platform: platform, needs_enrichment: needsEnrichment, timestamp: new Date().toISOString() } }];

const freetext = $('Validate and Normalize Input').item.json.freetext;
const prompt = `You are a cybersecurity expert. Analyze this attack and return ONLY valid JSON, no other text.

Attack: ${freetext}

Return exactly this structure:
{"title":"short title","mitre_tactics":["Credential Access"],"mitre_techniques":[{"id":"T1003.001","name":"technique name"}],"tools":["tool1"],"difficulty":"easy","execution_engine":"atomic","expected_detections":[{"detection":"what fires","severity":"high"}],"summary":"2 sentence description"}`;

return [{ json: { prompt: prompt } }];

const fs = require('fs');
const https = require('https');
const http = require('http');
const prompt = $input.first().json.prompt;
let provider = 'ollama', apiKey = '', model = '';
try {
  const cfg = JSON.parse(fs.readFileSync('/data/scenarios/ai-config.json', 'utf-8'));
  provider = cfg.provider || 'ollama';
  apiKey = cfg.apiKey || '';
  model = cfg.model || '';
} catch(e) {
  provider = $env.AI_PROVIDER || 'ollama';
  apiKey = $env.AI_API_KEY || '';
  model = $env.AI_MODEL || '';
}
const defaults = { anthropic: 'claude-sonnet-4-20250514', openai: 'gpt-4o', gemini: 'gemini-2.5-flash', ollama: $env.OLLAMA_MODEL || 'llama3.2:3b' };
const useModel = model || defaults[provider] || defaults.ollama;
let url, headers, body;
switch (provider) {
  case 'anthropic':
    url = 'https://api.anthropic.com/v1/messages';
    headers = { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' };
    body = JSON.stringify({ model: useModel, max_tokens: 4096, messages: [{ role: 'user', content: prompt }] });
    break;
  case 'openai':
    url = 'https://api.openai.com/v1/chat/completions';
    headers = { 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
    body = JSON.stringify({ model: useModel, messages: [{ role: 'user', content: prompt }] });
    break;
  case 'gemini':
    url = 'https://generativelanguage.googleapis.com/v1beta/models/' + useModel + ':generateContent?key=' + apiKey;
    headers = { 'Content-Type': 'application/json' };
    body = JSON.stringify({ contents: [{ parts: [{ text: prompt }] }] });
    break;
  default:
    url = ($env.OLLAMA_HOST || 'http://host.docker.internal:11434') + '/api/generate';
    headers = { 'Content-Type': 'application/json' };
    body = JSON.stringify({ model: useModel, prompt, stream: false });
}

const parsed = new URL(url);
const transport = parsed.protocol === 'https:' ? https : http;
const data = await new Promise((resolve, reject) => {
  const req = transport.request(url, { method: 'POST', headers, timeout: 120000 }, (res) => {
    let chunks = '';
    res.on('data', d => chunks += d);
    res.on('end', () => {
      if (res.statusCode >= 400) reject(new Error('AI provider error (' + provider + '): ' + res.statusCode + ' ' + chunks));
      else resolve(chunks);
    });
  });
  req.on('error', reject);
  req.on('timeout', () => { req.destroy(); reject(new Error('AI request timed out')); });
  if (body) req.write(body);
  req.end();
});

const response = JSON.parse(data);
return [{ json: { provider, response } }];

const { provider, response } = $input.first().json;
let text;
switch (provider) {
  case 'anthropic': text = response.content && response.content[0] ? response.content[0].text : ''; break;
  case 'openai': text = response.choices && response.choices[0] ? response.choices[0].message.content : ''; break;
  case 'gemini': text = response.candidates && response.candidates[0] ? response.candidates[0].content.parts[0].text : ''; break;
  default: text = response.response || '';
}
return [{ json: { response: text } }];

const raw = $input.first().json.response || '';
const cleaned = raw.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
let enriched;
try { enriched = JSON.parse(cleaned); } catch(e) {
  enriched = { title:'Custom Scenario', mitre_tactics:['Unknown'], mitre_techniques:[], tools:[], difficulty:'medium', execution_engine:'atomic', expected_detections:[], summary: raw.substring(0,200) };
}
const orig = $('Validate and Normalize Input').item.json;
const id = 'SCN-' + Date.now().toString().slice(-6);
return [{ json: {
  id: id,
  title: enriched.title,
  description: enriched.summary,
  mitre_tactics: enriched.mitre_tactics,
  mitre_techniques: enriched.mitre_techniques,
  tools: enriched.tools,
  difficulty: enriched.difficulty,
  platform: orig.platform,
  execution_engine: enriched.execution_engine,
  expected_detections: enriched.expected_detections,
  talking_points: { universal: [
    enriched.title + ' is commonly observed in MDR cases - analysts detect this in real time',
    'Watch the alert fire within seconds in the MDR console'
  ]},
  generated_at: orig.timestamp,
  source: 'ai-enriched',
  ai_provider: $('Call AI Provider').first().json.provider || 'unknown'
}}];

const fs = require('fs');
const filePath = '/data/scenarios/scenarios.json';
let db;
try { db = JSON.parse(fs.readFileSync(filePath,'utf8')); } catch(e) { db = { version:'1.0', last_updated:'', scenarios:[] }; }
const s = $input.first().json;
const idx = db.scenarios.findIndex(x => x.id === s.id);
if (idx >= 0) { db.scenarios[idx] = s; } else { db.scenarios.push(s); }
db.last_updated = new Date().toISOString().split('T')[0];
fs.writeFileSync(filePath, JSON.stringify(db,null,2),'utf8');
return [{ json: { success:true, scenario_id:s.id, scenario:s, total_scenarios:db.scenarios.length } }];

const fs = require('fs');
const filePath = '/data/scenarios/scenarios.json';
const orig = $('Validate and Normalize Input').item.json;
let db;
try { db = JSON.parse(fs.readFileSync(filePath,'utf8')); } catch(e) { return [{ json:{ error:'Could not read scenarios.json' } }]; }
const scenario = db.scenarios.find(s => s.id === orig.scenario_id);
if (!scenario) { return [{ json:{ error:'Scenario ' + orig.scenario_id + ' not found' } }]; }
const tp = (scenario.talking_points && scenario.talking_points[orig.industry]) || (scenario.talking_points && scenario.talking_points.universal) || [];
return [{ json:{ success:true, scenario:{ ...scenario, active_talking_points:tp } } }];
